using HaCreator.MapEditor;using HaCreator.MapEditor.Instance.Shapes;using HaCreator.MapEditor.UndoRedo;using System;using System.Collections.Generic;using System.Windows;
namespace HaCreator.GUI.InstanceEditor{public partial class TooltipInstanceEditor:EditorBase{public ToolTipInstance item;public TooltipInstanceEditor(ToolTipInstance item){InitializeComponent();this.item=item;InstanceEditorDialogSupport.SetInt(xInput,item.X);InstanceEditorDialogSupport.SetInt(yInput,item.Y);pathLabel.Text=HaCreatorStateManager.CreateItemDescription(item);useTitleBox.IsChecked=item.Title!=null;titleBox.Text=item.Title??string.Empty;useDescBox.IsChecked=item.Desc!=null;descBox.Text=item.Desc??string.Empty;UseTitle_Changed(null,null);UseDesc_Changed(null,null);}protected override void cancelButton_Click(object s,EventArgs e)=>Close();protected override void okButton_Click(object s,EventArgs e){lock(item.Board.ParentControl){int x=InstanceEditorDialogSupport.GetInt(xInput,item.X),y=InstanceEditorDialogSupport.GetInt(yInput,item.Y);List<UndoRedoAction>a=new();if(x!=item.X||y!=item.Y){a.Add(UndoRedoManager.ItemMoved(item,new Microsoft.Xna.Framework.Point(item.X,item.Y),new Microsoft.Xna.Framework.Point(x,y)));item.Move(x,y);}if(a.Count>0)item.Board.UndoRedoMan.AddUndoBatch(a);item.Title=useTitleBox.IsChecked==true?titleBox.Text:null;item.Desc=useDescBox.IsChecked==true?descBox.Text:null;}Close();}private void UseTitle_Changed(object s,RoutedEventArgs e){if(titleBox!=null)titleBox.IsEnabled=useTitleBox.IsChecked==true;}private void UseDesc_Changed(object s,RoutedEventArgs e){if(descBox!=null)descBox.IsEnabled=useDescBox.IsChecked==true;}private void Cancel_Click(object s,RoutedEventArgs e)=>cancelButton_Click(s,EventArgs.Empty);private void Ok_Click(object s,RoutedEventArgs e)=>okButton_Click(s,EventArgs.Empty);}}
